export function gpsToViewbox(lat: number, lng: number): { x: number; y: number } {
  const { x: xc, y: yc } = GEO_TRANSFORM.toViewbox;
  return {
    x: xc.a * lat + xc.b * lng + xc.c,
    y: yc.a * lat + yc.b * lng + yc.c,
  };
}

export function viewboxToGps(x: number, y: number): { lat: number; lng: number } {
  const { lat: lc, lng: gc } = GEO_TRANSFORM.toGPS;
  return {
    lat: lc.a * x + lc.b * y + lc.c,
    lng: gc.a * x + gc.b * y + gc.c,
  };
}